def _load_body_gltf():
    from pygltflib import GLTF2

    return GLTF2().load(str(BODY_GLB))


def _read_accessor_vec4(g, accessor_idx):
    """Decode a VEC4 accessor from the .glb binary blob -> list of 4-tuples."""
    import struct

    acc = g.accessors[accessor_idx]
    bv = g.bufferViews[acc.bufferView]
    blob = g.binary_blob()
    fmt_by_component = {5121: "B", 5123: "H", 5125: "I", 5126: "f"}
    fmt = fmt_by_component[acc.componentType]
    elem_size = struct.calcsize(fmt) * 4
    stride = bv.byteStride or elem_size
    base = (bv.byteOffset or 0) + (acc.byteOffset or 0)
    out = []
    for i in range(acc.count):
        off = base + i * stride
        out.append(struct.unpack_from("<" + fmt * 4, blob, off))
    return out


_GEO_LOD_RE = re.compile(r"^geo_(?P<region>[a-z0-9_]+)_lod(?P<lod>\d+)$")


@pytest.mark.integration
@skip_if_body_pointer
def test_body_glb_lod0_covers_exactly_the_8_geoset_regions():
    """I022: the eight geoset regions are each present at LOD0 (spec ④ §3/§5).

    The real ⑤/S4 body ships an authored LOD chain, so LOD0 is a subset of the
    full mesh list — this asserts the LOD0 coverage specifically, not the whole
    mesh count (which the blockout's `single`-LOD body could).
    """
    g = _load_body_gltf()
    lod0 = set()
    for m in g.meshes:
        mm = _GEO_LOD_RE.match(m.name)
        assert mm, f"body mesh '{m.name}' is not geoset-named (geo_<region>_lod<N>)"
        if int(mm.group("lod")) == 0:
            lod0.add(mm.group("region"))
    assert lod0 == set(GEOSET_REGIONS), (
        f"LOD0 regions {sorted(lod0)} != {sorted(GEOSET_REGIONS)}"
    )


@pytest.mark.integration
@skip_if_body_pointer
def test_body_glb_ships_authored_lod_chain_per_region():
    """I023: every geoset region carries LOD0 + at least one lower LOD.

    The real body is NOT the `single`-LOD blockout — each of the eight regions
    must ship an authored chain (geo_<region>_lod0 plus geo_<region>_lod1+),
    the exact condition validate_imports I023 enforces on the committed .glb.
    """
    g = _load_body_gltf()
    chain: dict[str, set[int]] = {}
    for m in g.meshes:
        mm = _GEO_LOD_RE.match(m.name)
        assert mm, f"body mesh '{m.name}' is not geoset-named"
        chain.setdefault(mm.group("region"), set()).add(int(mm.group("lod")))
    for region in GEOSET_REGIONS:
        lods = chain.get(region, set())
        assert 0 in lods, f"region '{region}' has no LOD0"
        assert any(lod >= 1 for lod in lods), (
            f"region '{region}' has no LOD1+ — a real body ships an authored "
            f"chain, not the blockout's 'single' exemption (I023)"
        )


@pytest.mark.integration
@skip_if_body_pointer
def test_body_glb_skin_joints_are_exactly_the_canonical_bone_set():
    """I020: every skin joint is canonical AND the full 63-bone set is bound."""
    g = _load_body_gltf()
    assert g.skins, "body .glb carries no skin"
    joint_names = set()
    for skin in g.skins:
        for j in skin.joints or []:
            joint_names.add(g.nodes[j].name)
    canonical = set(bones.bone_names())
    assert joint_names - canonical == set(), (
        f"non-canonical joints: {sorted(joint_names - canonical)}"
    )
    assert canonical - joint_names == set(), (
        f"canonical bones missing from skin: {sorted(canonical - joint_names)}"
    )


@pytest.mark.integration
@skip_if_body_pointer
def test_body_glb_vertices_have_at_most_4_influences():
    """E103/spec ④ §6: one JOINTS_0/WEIGHTS_0 set only — no JOINTS_1 spillover."""
    g = _load_body_gltf()
    for mesh in g.meshes:
        for prim in mesh.primitives:
            attrs = prim.attributes
            assert attrs.JOINTS_0 is not None, f"{mesh.name} is not skinned"
            assert attrs.WEIGHTS_0 is not None, f"{mesh.name} has no weights"
            assert getattr(attrs, "JOINTS_1", None) is None, (
                f"{mesh.name} carries a second influence set (>4 influences)"
            )


@pytest.mark.integration
@skip_if_body_pointer
def test_body_glb_weights_are_normalized():
    g = _load_body_gltf()
    for mesh in g.meshes:
        for prim in mesh.primitives:
            weights = _read_accessor_vec4(g, prim.attributes.WEIGHTS_0)
            comp = g.accessors[prim.attributes.WEIGHTS_0].componentType
            scale = 1.0 if comp == 5126 else (255.0 if comp == 5121 else 65535.0)
            for i, w in enumerate(weights):
                total = sum(w) / scale
                assert abs(total - 1.0) < 5e-3, (
                    f"{mesh.name} vertex {i} weight sum {total}"
                )


