def test_restyle_hair_bone_is_a_canonical_bone():
    """Hair single-influence skins to Head — which must be a canonical bone."""
    assert restyle_hair.HAIR_BONE in set(bones.bone_names())


def test_restyle_hair_mesh_name_is_not_geoset_named():
    """E104: an armor_model piece must NOT use geo_<region> geoset naming."""
    assert not restyle_hair.HAIR_MESH_NAME.startswith("geo_")


def test_restyle_hair_head_region_box_spans_the_head_geoset():
    """The fit target is the canonical head geoset span (crown ~1.72, base ~1.44)."""
    lo, hi = restyle_hair.head_region_box()
    assert hi[2] == pytest.approx(1.72, abs=0.05)  # crown at the Head bone tail
    assert lo[2] == pytest.approx(1.44, abs=0.05)  # base at the Neck head
    # A head-width box centred on the rig's vertical axis.
    assert lo[0] == pytest.approx(-hi[0], abs=1e-6)
    assert (hi[0] - lo[0]) > 0.0


def test_restyle_hair_fit_transform_scales_footprint_to_head_width():
    head_lo, head_hi = restyle_hair.head_region_box()
    mesh_min, mesh_max = (-0.5, -0.4, -0.3), (0.5, 0.4, 0.6)
    scale, offset = restyle_hair.fit_head_transform(
        mesh_min, mesh_max, head_lo, head_hi
    )
    head_w = max(head_hi[0] - head_lo[0], head_hi[1] - head_lo[1])
    mesh_w = max(mesh_max[0] - mesh_min[0], mesh_max[1] - mesh_min[1])
    assert scale == pytest.approx(head_w / mesh_w)


def test_restyle_hair_fit_transform_centres_volume_on_the_head():
    head_lo, head_hi = restyle_hair.head_region_box()
    mesh_min, mesh_max = (-0.5, -0.4, -0.3), (0.5, 0.4, 0.6)
    scale, offset = restyle_hair.fit_head_transform(
        mesh_min, mesh_max, head_lo, head_hi
    )

    def _c(lo, hi, i):
        return (lo[i] + hi[i]) / 2.0

    for i in range(3):
        placed_centre = _c(mesh_min, mesh_max, i) * scale + offset[i]
        assert placed_centre == pytest.approx(_c(head_lo, head_hi, i), abs=1e-6)
    # The seated hair centre sits within the head geoset's vertical span.
    placed_cz = _c(mesh_min, mesh_max, 2) * scale + offset[2]
    assert head_lo[2] <= placed_cz <= head_hi[2]


def test_restyle_hair_budget_is_low_poly_under_the_armor_ceiling():
    """Hair is a light attachment — target well under the armor_model 8k cap."""
    assert restyle_hair.TARGET_TRIS <= restyle_hair.MAX_TRIS
    assert restyle_hair.MAX_TRIS < 8_000  # armor_model L070 ceiling


