    from pygltflib import GLTF2

    g = GLTF2().load(str(hair_glb))
    assert g.skins, f"{hair_glb.name} carries no skin"
    joints = set()
    for skin in g.skins:
        for j in skin.joints or []:
            joints.add(g.nodes[j].name)
    canonical = set(bones.bone_names())
